package com.spendwise.prototype.ui; import android.net.Uri; import android.os.Bundle; import android.widget.ImageView; import androidx.appcompat.app.AppCompatActivity; import com.spendwise.prototype.R; import java.io.File; class PhotoViewerActivity:AppCompatActivity(){ override fun onCreate(s:Bundle?){ super.onCreate(s); setContentView(R.layout.activity_photo_viewer); val p=intent.getStringExtra("photo_path"); val iv=findViewById<ImageView>(R.id.ivFull); if(p!=null&&File(p).exists()) iv.setImageURI(Uri.fromFile(File(p))) } }